// Jarvis Brain: Market Data -> Ollama -> Jarvis Webhook
const JARVIS_TOKEN = '29bfff2625fe5726dfd9bae5810fec62aee1f92c96a0a0803f0e0b11c42bffaf';
const API_BASE = 'https://web-production-d57ac.up.railway.app';
const OLLAMA_URL = 'http://host.docker.internal:11434';

// Step 1: Fetch market data from Railway
let marketData = {};
try {
  const statusResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${API_BASE}/api/status`,
    returnFullResponse: true,
  });
  marketData = statusResp.body || {};
} catch (e) {
  marketData = { error: 'Could not fetch market data', detail: e.message };
}

// Clean non-ASCII characters
const cleanData = {};
for (const [k, v] of Object.entries(marketData)) {
  if (typeof v === 'string') {
    cleanData[k] = v.replace(/[^\x20-\x7E]/g, '');
  } else {
    cleanData[k] = v;
  }
}

// Step 2: Call Ollama locally
let ollamaResult = {};
try {
  const prompt = `Current ETH trading bot data: ${JSON.stringify(cleanData)}\n\nAnalyze this data and respond ONLY with a valid JSON object:\n{"ml_confidence_threshold": 0.42, "risk_multiplier": 1.0, "emergency_stop": false, "active_edges": ["BREAKOUT","NORMAL","BB_BOUNCE","MACD_CROSS","RANGE_SUP"], "reason": "short reason"}\n\nRules:\n- ml_confidence_threshold: 0.30-0.90 (higher=fewer trades, default 0.42)\n- risk_multiplier: 0.1-5.0 (default 1.0, lower in high volatility)\n- emergency_stop: true ONLY for extreme danger\n- active_edges: sideways market use OS-FAST,BB_BOUNCE,RANGE_SUP. trending use BREAKOUT,NORMAL,MACD_CROSS\n- Be conservative. When in doubt, use defaults.`;

  // Try localhost first, then host.docker.internal (for Docker-based n8n)
  let ollamaHost = 'http://localhost:11434';
  let ollamaResp;
  try {
    ollamaResp = await this.helpers.httpRequest({
      method: 'POST',
      url: `${ollamaHost}/api/generate`,
      body: {
        model: 'qwen2.5-coder:14b',
        prompt: prompt,
        stream: false,
        format: 'json'
      },
      returnFullResponse: true,
      timeout: 120000,
    });
  } catch (e1) {
    // Fallback: try host.docker.internal (Docker)
    ollamaHost = 'http://host.docker.internal:11434';
    ollamaResp = await this.helpers.httpRequest({
      method: 'POST',
      url: `${ollamaHost}/api/generate`,
      body: {
        model: 'qwen2.5-coder:14b',
        prompt: prompt,
        stream: false,
        format: 'json'
      },
      returnFullResponse: true,
      timeout: 120000,
    });
  }

  const responseText = ollamaResp.body?.response || '{}';
  ollamaResult = JSON.parse(responseText);
} catch (e) {
  ollamaResult = {
    ml_confidence_threshold: 0.42,
    risk_multiplier: 1.0,
    emergency_stop: false,
    reason: `Ollama error, using defaults: ${e.message}`
  };
}

// Step 3: Push to Jarvis Webhook
let webhookResult = {};
try {
  const postResp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${API_BASE}/api/jarvis/update_regime`,
    headers: {
      'X-Jarvis-Token': JARVIS_TOKEN,
      'Content-Type': 'application/json',
    },
    body: ollamaResult,
    returnFullResponse: true,
  });
  webhookResult = postResp.body || {};
} catch (e) {
  webhookResult = { error: 'Webhook failed', detail: e.message };
}

return [{
  json: {
    status: 'ok',
    timestamp: new Date().toISOString(),
    market_data: cleanData,
    ollama_analysis: ollamaResult,
    webhook_result: webhookResult,
  }
}];
